prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelName ?choreo ?parallelGw ?gwName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "0b4394edaa09437d93cc54c78c0180cb" ;
         bbo:name ?modelName .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?parallelGw a bboExt:ParallelGateway ;
               tai:belongsTo ?choreo .

  OPTIONAL { ?parallelGw bbo:name ?gwName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?orig ?norm ?choreo ?task WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName .

  OPTIONAL { ?model tai:originalId ?orig . }
  OPTIONAL { ?model tai:normalizedId ?norm . }

  FILTER(
    (BOUND(?orig) && ?orig = "0b4394edaa09437d93cc54c78c0180cb") ||
    (BOUND(?norm) && ?norm = "0b4394edaa09437d93cc54c78c0180cb") ||
    CONTAINS(LCASE(STR(?orig)), LCASE("0b4394edaa09437d93cc54c78c0180cb")) ||
    CONTAINS(LCASE(STR(?norm)), LCASE("0b4394edaa09437d93cc54c78c0180cb"))
  )

  ?choreo tai:belongsTo ?model .
  OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gwType ?gw ?gwName (COUNT(DISTINCT ?outEdge) AS ?outgoingFlows) WHERE {
  {
    ?gw a bboExt:ParallelGateway .
    BIND("ParallelGateway" AS ?gwType)
  }
  UNION
  {
    ?gw a bboExt:ExclusiveGateway .
    BIND("ExclusiveGateway" AS ?gwType)
  }
  UNION
  {
    ?gw a bboExt:EventBasedGateway .
    BIND("EventBasedGateway" AS ?gwType)
  }
  ?gw tai:belongsTo ?choreo .

  ?model a bboExt:Model ;
         tai:originalId "0b4394edaa09437d93cc54c78c0180cb" ;
         tai:belongsTo ?org .
  ?choreo tai:belongsTo ?model .

  OPTIONAL { ?gw bbo:name ?gwName . }

  OPTIONAL {
    ?outEdge a bbo:SequenceFlow ;
             bbo:has_sourceRef ?gw ;
             bbo:has_targetRef ?tgt .
  }
}
GROUP BY ?gwType ?gw ?gwName
ORDER BY ?gwType
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?gwType ?gw ?gwName WHERE {
  VALUES ?choreo {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-279addb4-f0c7-41db-a5b8-a3b9dd40b6dc>
  }

  {
    ?gw a bboExt:ParallelGateway .
    BIND("ParallelGateway" AS ?gwType)
  }
  UNION
  {
    ?gw a bboExt:ExclusiveGateway .
    BIND("ExclusiveGateway" AS ?gwType)
  }
  UNION
  {
    ?gw a bboExt:EventBasedGateway .
    BIND("EventBasedGateway" AS ?gwType)
  }

  ?gw tai:belongsTo ?choreo .
  OPTIONAL { ?gw bbo:name ?gwName . }
}
ORDER BY ?gwType ?gwName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?from ?fromName (COUNT(DISTINCT ?to) AS ?outDegree) WHERE {
  VALUES ?choreo {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-279addb4-f0c7-41db-a5b8-a3b9dd40b6dc>
  }
  ?from tai:belongsTo ?choreo .

  ?edge a bbo:SequenceFlow ;
        bbo:has_sourceRef ?from ;
        bbo:has_targetRef ?to .

  OPTIONAL { ?from bbo:name ?fromName . }
}
GROUP BY ?from ?fromName
HAVING(COUNT(DISTINCT ?to) > 1)
ORDER BY DESC(?outDegree)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(*) AS ?seqCount) (SAMPLE(?s) AS ?exampleSource) (SAMPLE(?t) AS ?exampleTarget) WHERE {
  VALUES ?choreo {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-279addb4-f0c7-41db-a5b8-a3b9dd40b6dc>
  }

  ?s tai:belongsTo ?choreo .
  ?t tai:belongsTo ?choreo .

  ?edge a bbo:SequenceFlow ;
        bbo:has_sourceRef ?s ;
        bbo:has_targetRef ?t .
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?containerType ?container ?gwParCount ?seqCount WHERE {
  {
    ?container a bboExt:Choreography ;
              tai:belongsTo ?model .
    BIND("Choreography" AS ?containerType)
  }
  UNION
  {
    ?container a bboExt:Collaboration ;
              tai:belongsTo ?model .
    BIND("Collaboration" AS ?containerType)
  }
  ?model a bboExt:Model ;
         tai:originalId "0b4394edaa09437d93cc54c78c0180cb" ;
         tai:belongsTo ?org .

  {
    SELECT ?container (COUNT(DISTINCT ?gw) AS ?gwParCount) WHERE {
      ?gw a bboExt:ParallelGateway ; tai:belongsTo ?container .
    } GROUP BY ?container
  }
  OPTIONAL {
    SELECT ?container (COUNT(DISTINCT ?edge) AS ?seqCount) WHERE {
      ?edge a bbo:SequenceFlow ;
            bbo:has_sourceRef ?s ;
            bbo:has_targetRef ?t .
      ?s tai:belongsTo ?container .
      ?t tai:belongsTo ?container .
    } GROUP BY ?container
  }
}
ORDER BY ?gwParCount DESC(?gwParCount)
LIMIT 25
